   203→          async () => {
   204→            const workerContext: WorkerJobContext<T> = {
   205→              id: job.id ?? 'unknown',
   206→              name: job.name,
   207→              data: job.data,
   208→              attemptsMade: job.attemptsMade,
   209→              updateProgress: async (progress) => {
