   344→    health.push({
   345→      queueName,
   346→      description: registered.description,
   347→      isRunning: registered.worker.isRunning(),
   348→      isPaused: registered.worker.isPaused(),
   349→    });
   350→  }
   351→
   352→  return health;
   353→}
